var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"흥, 건방져. 당신이 직접 나한테 찾아와야 정상아냐?","JPN":"ふん、生意気ね。あんたのほうから会いに来るのが普通じゃないの？","ENG":"Hmph, who do you think you are? Shouldn't you be coming to see me?","TWN":"哼，真狂妄。應該是你親自來找我才對吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"당신이니까 이 정도 무례함은 용서해 줄게. 그래서 뭐 때문에 불렀어?","JPN":"無礼だけど、あんただから許してあげるわ。で、なんで呼んだの？","ENG":"I'll let it slide because it's you. So? Why did you want to see me?","TWN":"看在是你的份上，我就原諒你的無禮吧。所以呢？找我來幹嘛？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"뭐?! 이사장한테 추천서를 받았다고? 이리 줘봐!","JPN":"はあ！？　理事長に推薦状をもらった！？　よこしなさい！","ENG":"What?! You got a recommendation letter from the Chairwoman? Give it here!","TWN":"什麼？！你說理事長寫推薦信給你？拿來我看看！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"우수한 아이니까, 한번 믿고 지켜봐 주세요……?","JPN":"優秀な子なので、信じて見守ってください……？","ENG":"\\"She's an excellent student, so give her a chance\\"...?","TWN":"這孩子很優秀，請給她一次機會……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"하하, 설마 그 이사장이 추천서를 보낼 줄이야. 뭐, 이런 대접은 익숙하지만…….","JPN":"あはは、まさかあの理事長が推薦状を送るとはね。まあ、優遇されるのには慣れているけど。","ENG":"Haha, I never thought she'd write me a recommendation letter. Well, I am used to these kinds of special treatments...","TWN":"哈哈，沒想到理事長會幫我寫推薦信。不過，這種事我很習慣啦……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"대신 출근하는 동안 코스프레 차림은 지양해달라고?","JPN":"その代わり、出勤の時はコスプレはやめてほしい……？","ENG":"But I should refrain from cosplaying while I'm at work?","TWN":"但你有個條件，就是不能在上班時間玩Cosplay？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"이건 코스프레 같은 게 아냐! 내 비장의 무장이라고.","JPN":"これはコスプレじゃないわよ！　私のとっておきの武装なの。","ENG":"This isn't cosplay! This is my secret weapon.","TWN":"這才不是什麼Cosplay！這是我的秘密武裝！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"아, 아무튼 됐어! 빨리 계약이나 해!","JPN":"と、とにかく！　早く契約しましょ！","ENG":"A-anyway, fine! Let's get this over with already!","TWN":"隨，隨便啦！趕快簽一簽啦！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"자, 싸인 끝! 그럼 바로 첫 번째 임무부터 안내해 줘.","JPN":"ほら、サイン！　じゃ、さっさと初任務を案内してちょうだい。","ENG":"Okay, the contract is signed! Now, tell me what my first mission is going to be.","TWN":"好了，簽完了！現在就帶我去執行第一個任務吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"난 나름 경력자니까, 당연히 이면세계에서 침식체 소탕 임무겠지?","JPN":"私は経験者だから、当然裏世界で侵食体を掃討する任務をくれるんでしょ？","ENG":"I have a lot of experience, so I'm sure you'll be giving me a mission to eliminate C.O.s in the Counterside, right?","TWN":"我可是有經驗的人，任務應該是去掃蕩異界的侵蝕體吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"……인턴부터 시작하자고?! 서, 서류 정리?!","JPN":"……最初はインターン！？　しょ、書類まとめですって！？","ENG":"...I'm starting as an intern?! O-organizing paperwork?!","TWN":"……什麼？從實習生開始？還要整理文件？！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"말도 안 돼! 약속이랑 다르잖아!","JPN":"あり得ないわ！　約束と違うじゃない！","ENG":"That's ridiculous! This isn't what I signed up for!","TWN":"這什麼鬼！和說好的不一樣吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"내가 모처럼 코스프레…… 가 아니라 완전 무장으로 와 줬는데 이러기냐고!","JPN":"せっかくコスプレ……じゃなくて、完全武装で来てやったのにあんまりよ！","ENG":"I even cosplayed– I mean, came here fully geared up, and this is how you treat me?","TWN":"我還特地Cosplay…不對，是全副武裝來的欸！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"영웅으로 성장한 사람들도 처음엔 작은 일부터 시작해 왔다고?","JPN":"英雄になった人たちも、最初は些細なことから始めた……？","ENG":"Even heroes started with small tasks?","TWN":"英雄也是從基層做起的？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"처음부터 위험한 임무에 투입시키면 이사장을 볼 면목이 없어서……?","JPN":"最初から危険な任務に送り出すのは、理事長に顔向けできない……？","ENG":"And you won't be able to look at Ms. Chairwoman in the face if you deploy me into a dangerous mission from the get-go...?","TWN":"要是一開始就讓我去執行危險的任務，你拿什麼臉去見理事長……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"흥! 일리가 있네. 그럼 이 서류부터 정리하면 되는 거지?","JPN":"ふん！　まあ、一理ある話ね。じゃあこの書類から整理すればいいわけ？","ENG":"Hmph! Sounds fair enough. So, I just need to organize these documents, right?","TWN":"哼！有道理。先整理這些文件就好是吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"좋아. 엘리트답게 1시간 만에 해치워주겠어!","JPN":"いいわ。エリートらしく1時間で片付けてやる！","ENG":"Okay. I'll finish it all up within an hour, as an elite should!","TWN":"好，讓你見識精英的效率，1小時內幫你搞定！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"그리고 이거 다 끝내면 다른 일도 시켜 주기로 약속한 거다? 응?!","JPN":"これ終わったら他の仕事もやらせてくれるわよね？　ね？","ENG":"Also, you have to promise to give me more work after I'm done with this, okay?!","TWN":"這些全部做完後，你要分配其他任務給我喔，知道嗎？說好囉？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};